/// <summary>
/// Extension of the <c>CustInvoiceTrans</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(CustInvoiceTrans))]
final class CustInvoiceTransETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>initFromSalesLine</c> method to populate the fields of the ETGSPAIN model.
/// </summary>
/// <param name="salesLine">SalesLine record</param>
/// <param name="_salesParmLine">SalesParmLine record</param>
void initFromSalesLine(SalesLine salesLine, SalesParmLine _salesParmLine)
{
    next initFromSalesLine(salesLine, _salesParmLine);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        this.ETGSPAINPurchUnloadPortId              = salesLine.ETGSPAINPurchUnloadPortId;
        this.ETGSPAINPurchLoadPortId                = salesLine.ETGSPAINPurchLoadPortId;

        this.ETGSPAINCustSalesReference             = salesLine.ETGSPAINCustSalesReference;
        this.ETGSPAINInventLicensePlate             = salesLine.ETGSPAINInventLicensePlate;
        this.ETGSPAINInventPackingSlipTransitId     = salesLine.ETGSPAINInventPackingSlipTransitId;
        this.ETGSPAINSalesCustomerWithdrawalDate    = salesLine.ETGSPAINSalesCustomerWithdrawalDate;
    }
}
